import{_ as a,c as o,o as t,a1 as r}from"./chunks/framework.DILC4Csi.js";const m=JSON.parse('{"title":"Acerca de: Introducción a OpenCodeDocs | opencodedocs","description":"Conoce OpenCodeDocs, el sitio de tutoriales líder en el ecosistema AI. Análisis profundo de proyectos open source, tutoriales de alta calidad basados en código fuente y 100% funcionales.","frontmatter":{"title":"Acerca de: Introducción a OpenCodeDocs | opencodedocs","sidebarTitle":"Entender la visión del proyecto","subtitle":"Acerca de: Introducción a OpenCodeDocs | opencodedocs","description":"Conoce OpenCodeDocs, el sitio de tutoriales líder en el ecosistema AI. Análisis profundo de proyectos open source, tutoriales de alta calidad basados en código fuente y 100% funcionales."},"headers":[],"relativePath":"es/about.md","filePath":"es/about.md"}'),n={name:"es/about.md"};function i(s,e,c,d,l,u){return t(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="acerca-de-opencodedocs" tabindex="-1">Acerca de OpenCodeDocs <a class="header-anchor" href="#acerca-de-opencodedocs" aria-label="Permalink to &quot;Acerca de OpenCodeDocs&quot;">​</a></h1><blockquote><p><strong>Sitio de tutoriales líder en el ecosistema AI · Basado en código fuente · 100% funcional</strong></p></blockquote><h2 id="nuestra-vision" tabindex="-1">Nuestra visión <a class="header-anchor" href="#nuestra-vision" aria-label="Permalink to &quot;Nuestra visión&quot;">​</a></h2><p>Las herramientas de AI evolucionan rápidamente, la documentación oficial se queda atrás, los tutoriales en línea se vuelven obsoletos — queremos cambiar todo esto.</p><p>OpenCodeDocs analiza en profundidad el código fuente y los ejemplos oficiales de proyectos open source, extrae la lógica central y garantiza a través de validación automatizada que cada línea de código funcione.</p><p>Cuando los proyectos se actualizan, nuestros tutoriales se actualizan sincrónicamente. Cada tutorial indica claramente la versión de Git Commit, para que sepas en qué versión se basa el código.</p><p><strong>Nuestro objetivo es convertirnos en el &quot;Verified Standard&quot; del mundo de herramientas AI.</strong></p><h2 id="licencia-de-codigo-abierto" tabindex="-1">Licencia de código abierto <a class="header-anchor" href="#licencia-de-codigo-abierto" aria-label="Permalink to &quot;Licencia de código abierto&quot;">​</a></h2><p>Creemos que la apertura genera confianza. Bienvenidas las contribuciones, correcciones y complementos de la comunidad.</p><h3 id="contenido-de-los-tutoriales" tabindex="-1">Contenido de los tutoriales <a class="header-anchor" href="#contenido-de-los-tutoriales" aria-label="Permalink to &quot;Contenido de los tutoriales&quot;">​</a></h3><p><strong>Licencia</strong>: <a href="https://creativecommons.org/licenses/by-nc-sa/4.0/" target="_blank" rel="noreferrer">CC-BY-NC-SA 4.0</a> Atribución - No comercial - Compartir igual. Permite la reproducción y adaptación, pero se debe indicar la fuente, no se puede usar con fines comerciales y debe compartirse bajo la misma licencia.</p><h3 id="herramienta-de-construccion" tabindex="-1">Herramienta de construcción <a class="header-anchor" href="#herramienta-de-construccion" aria-label="Permalink to &quot;Herramienta de construcción&quot;">​</a></h3><p><strong>VitePress</strong>: Este proyecto utiliza <a href="https://vitepress.dev/" target="_blank" rel="noreferrer">VitePress</a> para la construcción. Gracias al equipo de VitePress por proporcionar un generador de sitios estáticos tan excelente.</p><p><a href="https://github.com/vbgate/opencodedocs" target="_blank" rel="noreferrer">Ver repositorio en GitHub</a></p><h2 id="contactanos" tabindex="-1">Contáctanos <a class="header-anchor" href="#contactanos" aria-label="Permalink to &quot;Contáctanos&quot;">​</a></h2><ul><li><strong>Email</strong>: <a href="mailto:vbgatecom@gmail.com" target="_blank" rel="noreferrer">vbgatecom@gmail.com</a></li><li><strong>Twitter</strong>: <a href="https://x.com/codingzys" target="_blank" rel="noreferrer">@codingzys</a></li><li><strong>GitHub</strong>: <a href="https://github.com/vbgate/opencodedocs" target="_blank" rel="noreferrer">github.com/vbgate/opencodedocs</a></li></ul>',16)])])}const b=a(n,[["render",i]]);export{m as __pageData,b as default};
